#!/usr/bin/env sage
# verify_universal_obstruction.py
# Given CM modulus results, computes S0, S1 for each family/discriminant
# and checks the universal transcendental obstruction.
# Usage: sage verify_universal_obstruction.py --results cm_results_merged.csv

import argparse, csv, sys, time
from mpmath import mp

mp.mp.dps = 800

# === HYPERGEOMETRIC PARAMETERS (all 16 families, duplicate-free) ===
