def pochhammer_list(vals, n):
    """Compute product of (v)_n for all v in vals using mpmath rgamma."""
    result = mp.mpf(1)
    for v in vals:
        result *= mp.rf(v, n)
    return result

def compute_series(a_list, b_list, k, z0, max_n=20):
    """Compute S0, S1 for the hypergeometric series at modulus z0."""
    s0 = mp.mpf(0)
    s1 = mp.mpf(0)
    for n in range(max_n + 1):
        num = pochhammer_list(a_list, n)
        den = pochhammer_list(b_list, n) * mp.factorial(n)**k
        term = (num / den) * (z0 ** n)
        s0 += term
        s1 += term * n
    return s0, s1

# === MAIN ===
parser = argparse.ArgumentParser()
parser.add_argument("--results", required=True, help="Merged CM results CSV")
parser.add_argument("--families", nargs="*", default=list(FAMILY_PARAMS.keys()),
                    help="Families to verify (default: all)")
parser.add_argument("--pslq", action="store_true", help="Run PSLQ search (slower)")
args = parser.parse_args()

# Read CM results
cm_data = {}
with open(args.results) as f:
    for row in csv.DictReader(f):
        key = (row["Family"], int(row["d"]))
        if row["Status"] == "OK" and row["z0_CM"]:
            cm_data[key] = mp.mpf(row["z0_CM"])

print(f"Loaded {len(cm_data)} CM modulus values")
print(f"Testing families: {args.families}\n")

# Verify each
header = ["Family", "d", "z0_CM", "S0", "S1", "S1/S0", "C~A*pi?", "Prediction"]
rows = []

for fam_id in args.families:
    params = FAMILY_PARAMS[fam_id]
    for d, _, _ in [(1,"",1728), (2,"",8000), (3,"",0), (7,"",-3375), (11,"",-32768),
                      (19,"",-884736), (43,"",-884736000), (67,"",-147197952000), (163,"",-262537412640768000)]:
        key = (fam_id, d)
        if key not in cm_data:
            rows.append([fam_id, d, "MISSING", None, None, None, None, "No CM data"])
            continue
        
        z0_cm = cm_data[key]
        s0, s1 = compute_series(params["a"], params["b"], params["k"], z0_cm)
        
        ratio = float(s1 / s0) if float(s0) > 0 else 0
        obstruction = "YES (S1 << S0 => C~A*pi impossible)" if ratio < 1e-6 else "CHECK"
        
        # Run PSLQ if requested
        prediction = ""
        if args.pslq and obstruction == "CHECK":
            try:
                vec = [float(mp.pi * s0), float(mp.pi * s1), float(-mp.sqrt(s0*s0 + s1*s1))]
                rel = gp.lindep(vec, 20)
                prediction = f"PSLQ: {rel}" if rel else "No integer relation"
            except:
                prediction = "PSLQ failed"
        
        rows.append([fam_id, d, f"{float(z0_cm):.4e}", f"{float(s0):.8f}",
                     f"{float(s1):.4e}", f"{ratio:.4e}", obstruction, prediction])
        
        print(f"[{fam_id}] d={d:3d}: z0={float(z0_cm):.4e}  S0={float(s0):.6f}  S1={float(s1):.4e}  => {obstruction}")

# Save results
outfile = "obstruction_results.csv"
with open(outfile, "w", newline="") as f:
    w = csv.writer(f)
    w.writerow(header)
    w.writerows(rows)

print(f"\nResults saved to {outfile}")

# Summary: count obstruction YES vs CHECK
yes_count = sum(1 for r in rows if r[6] and "YES" in str(r[6]))
check_count = sum(1 for r in rows if r[6] and "CHECK" in str(r[6]))
print(f"Structural obstruction confirmed: {yes_count}/{len(rows)}")
if check_count > 0:
    print(f"Needs further check: {check_count}/{len(rows)}")
